const saludos = ['hola','hi','hello','buenas','buenos','buen','inicio','menu','start','0'];
let msg;
if (saludos.some(s => text.startsWith(s)) || text === '') {
  msg = MENU;
} else if (text === '1' || text.includes('servicio') || text.includes('precio') || text.includes('corte')) {
  msg = SERVICIOS;
} else if (text === '2' || text.includes('agendar') || text.includes('cita') || text.includes('hora') || text.includes('appointment')) {
  msg = AGENDAR;
} else if (text === '3' || text.includes('horario') || text.includes('abierto') || text.includes('cierra')) {
  msg = HORARIOS;
} else if (text === '4' || text.includes('ubicac') || text.includes('direcc') || text.includes('donde') || text.includes('llegar')) {
  msg = UBICACION;
} else if (text.includes('barba') || text.includes('afeit') || text.includes('diseño')) {
  msg = SERVICIOS;
} else {
  msg = MENU;
}

return [{ json: { from, mensaje_respuesta: msg } }];
